CREATE TABLE process_to_system
(
	id serial,
	process_id integer NOT NULL,
	system_id integer DEFAULT NULL,
	CONSTRAINT pk_process_to_system PRIMARY KEY (id)
	, CONSTRAINT fk_process_to_system_to_process FOREIGN KEY (process_id) REFERENCES process (id) MATCH SIMPLE ON UPDATE NO ACTION ON DELETE NO ACTION
	, CONSTRAINT fk_process_to_system_to_system FOREIGN KEY (system_id) REFERENCES systems (id) MATCH SIMPLE ON UPDATE NO ACTION ON DELETE NO ACTION
);
CREATE INDEX i_process_to_system_process ON process_to_system (process_id);
CREATE INDEX i_process_to_system_system ON process_to_system (system_id);
